import 'category.dart';enum BudgetFrequency { monthly, weekly, custom }class Budget {  final String id;  final String name;  final double totalAmount;  final double spentAmount;  final List<Category> categories;  final BudgetFrequency frequency;  final DateTime startDate;  final DateTime? endDate;  final bool rolloverOverspend;  final double alertThreshold;  Budget({    required this.id,    required this.name,    required this.totalAmount,    required this.spentAmount,    required this.categories,    required this.frequency,    required this.startDate,    this.endDate,    this.rolloverOverspend = false,    this.alertThreshold = 0.8,  });  double get remainingAmount => totalAmount - spentAmount;  double get progress => spentAmount / totalAmount;  bool get isOverBudget => spentAmount > totalAmount;  Budget copyWith({    String? id,    String? name,    double? totalAmount,    double? spentAmount,    List<Category>? categories,    BudgetFrequency? frequency,    DateTime? startDate,    DateTime? endDate,    bool? rolloverOverspend,    double? alertThreshold,  }) {    return Budget(      id: id ?? this.id,      name: name ?? this.name,      totalAmount: totalAmount ?? this.totalAmount,      spentAmount: spentAmount ?? this.spentAmount,      categories: categories ?? this.categories,      frequency: frequency ?? this.frequency,      startDate: startDate ?? this.startDate,      endDate: endDate ?? this.endDate,      rolloverOverspend: rolloverOverspend ?? this.rolloverOverspend,      alertThreshold: alertThreshold ?? this.alertThreshold,    );  }}